import { createSlice } from '@reduxjs/toolkit'

const initialState = {
    items : [],
    originalTotal :0,
    finalTotal : 0
}

export const cartSlice = createSlice({
  name: 'cart',
  initialState,
  reducers: {
    addToCart: (state,{payload}) => {
     state.items.push(payload);
     state.originalTotal += Number(payload?.original_price);
     state.finalTotal += Number(payload?.final_price);

     localStorage.setItem("cart",JSON.stringify(state))
    },
    
    emptyCart : (state)=>{

    },

    qtyChanges : ()=>{

    },


    lsToCart : (state) => {
      const cart =  JSON.parse(localStorage.getItem("cart"))
      if(cart) {
        state.items = cart.items,
        state.originalTotal = cart.finalTotal,
        state.finalTotal = cart.finalTotal
      }
    }
  },
})

// Action creators are generated for each case reducer function
export const { addToCart, emptyCart, qtyChanges,lsToCart } = cartSlice.actions

export default cartSlice.reducer